const j = $json || {};
const now = new Date().toISOString();
const critic = j.image_native_critic || {};
const gate = j.gate || {};

const reasons = [
  String(critic.rejection_reason || '').trim(),
  ...(Array.isArray(gate.reasons) ? gate.reasons : []),
].filter(Boolean);

return [{
  json: {
    ctx: j.ctx || {},
    reject: {
      reject_id: `tvpx_rej_${String(j.ctx?.trace_id || 'trace').trim()}_scene_seed_${now.replace(/[:.]/g, '')}`,
      trace_id: String(j.ctx?.trace_id || '').trim(),
      stage_name: 'scene_seed_gate',
      rejection_reason: reasons.join(' | ') || 'Rejected by deterministic image-native gate.',
      raw_output_json: JSON.stringify({
        gate,
        critic,
        scene_seed: j.scene_seed || {},
        archetype_route: j.archetype_route || {},
      }),
      created_at: now,
    },
  },
}];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const j = $json || {};
const ctx = j.ctx || {};
const bundle = j.bundle || {};
const seed = j.scene_seed || {};
const critic = j.image_native_critic || {};
const route = j.archetype_route || {};
const gate = j.gate || {};
const guardrail = j.archetype_guardrail_row || {};
const now = new Date().toISOString();

const fragmentIds = Array.isArray(bundle.fragment_ids) ? bundle.fragment_ids.filter(Boolean) : [];
if (!fragmentIds.length) {
  throw new Error('TVPX__20: scene seed cannot be written without fragment_ids.');
}

const seedHashBase = [
  ctx.trace_id,
  ctx.crawl_run_id,
  ctx.source_id,
  route.archetype_id,
  seed.scene_kernel,
  fragmentIds.join(',')
].join('::');

const sceneSeedId = `tvpx_ss_${fnv1a(seedHashBase)}`;

const row = {
  scene_seed_id: sceneSeedId,
  trace_id: String(ctx.trace_id || '').trim(),
  crawl_run_id: String(ctx.crawl_run_id || '').trim(),
  origin_type: 'crawler',
  source_id: String(ctx.source_id || '').trim(),
  parent_scene_seed_id: null,
  root_scene_seed_id: sceneSeedId,
  seed_fragment_ids_json: JSON.stringify(fragmentIds),
  archetype_id: String(route.archetype_id || '').trim(),
  subject_mode: String(seed.subject_mode || '').trim(),
  scene_kernel: String(seed.scene_kernel || '').trim(),
  concept_thesis: String(seed.concept_thesis || '').trim(),
  symbolic_tension: String(seed.symbolic_tension || '').trim(),
  material_anchor: String(seed.material_anchor || '').trim(),
  spatial_directive: String(seed.spatial_directive || '').trim(),
  palette_directive: String(seed.palette_directive || '').trim(),
  texture_directive: String(seed.texture_directive || '').trim(),
  dominant_subject: String(seed.dominant_subject || '').trim(),
  setting_family: String(seed.setting_family || '').trim(),
  ceremonial_logic: String(seed.ceremonial_logic || '').trim(),
  surreal_pressure: String(seed.surreal_pressure || '').trim(),
  surreal_mechanism: String(seed.surreal_mechanism || '').trim(),
  negative_space_note: String(seed.negative_space_note || '').trim(),
  omission_notes: String(seed.omission_notes || '').trim(),
  prop_manifest_json: JSON.stringify(seed.prop_manifest || { hero_props: [], supporting_props: [] }),
  forbidden_excess_json: JSON.stringify(Array.isArray(seed.forbidden_excess) ? seed.forbidden_excess : []),
  render_budget_json: JSON.stringify(seed.render_budget || { max_named_props: 4, max_background_motifs: 2, max_prompt_words: 115 }),
  quality_score: Number(critic.score || 0),
  brand_fit_score: Number(critic.brand_fit || 0),
  reference_alignment_score: Number(critic.reference_alignment || 0),
  family_guardrail_score: Number(gate.family_guardrail_score || critic.family_guardrail_score || 0),
  negative_space_force_score: Number(critic.negative_space_force || 0),
  prop_discipline_score: Number(critic.prop_discipline || 0),
  guardrail_failures_json: JSON.stringify(Array.isArray(gate.reasons) ? gate.reasons : []),
  state: 'ready',
  lock_owner: '',
  lock_expires_at: null,
  used_count: 0,
  last_used_at: null,
  rejection_reason: '',
  created_at: now,
  updated_at: now
};

return [{
  json: {
    ctx: {
      ...ctx,
      scene_seed_id: sceneSeedId,
      root_scene_seed_id: sceneSeedId,
    },
    scene_seed_row: row,
    archetype_guardrail_row: guardrail
  }
}];

function parseJsonMaybe(value, fallback) {
  if (Array.isArray(value) || (value && typeof value === 'object')) return value;
  const text = String(value || '').trim();
  if (!text) return fallback;
  try { return JSON.parse(text); } catch { return fallback; }
}

function clean(v) {
  return String(v || '').toLowerCase().replace(/[^a-z0-9\s-]/g, ' ').replace(/\s+/g, ' ').trim();
}

function blob(parts) {
  return parts.map(v => String(v || '')).join(' ').toLowerCase();
}

function hasAny(text, terms) {
  const t = clean(text);
  return (terms || []).some(term => {
    const needle = clean(term);
    return needle && (` ${t} `).includes(` ${needle} `);
  });
}

function hitCount(text, terms) {
  const t = clean(text);
  return (terms || []).filter(term => {
    const needle = clean(term);
    return needle && (` ${t} `).includes(` ${needle} `);
  }).length;
}

const j = $json || {};
const seed = j.scene_seed || {};
const critic = j.image_native_critic || {};
const guard = j.archetype_guardrail_row || {};

const positiveBlob = blob([
  seed.scene_kernel,
  seed.concept_thesis,
  seed.symbolic_tension,
  seed.material_anchor,
  seed.spatial_directive,
  seed.palette_directive,
  seed.texture_directive,
  seed.dominant_subject,
  seed.setting_family,
  seed.ceremonial_logic,
  seed.surreal_pressure,
  seed.negative_space_note,
  seed.surreal_mechanism
]);

const propManifest = parseJsonMaybe(seed.prop_manifest, parseJsonMaybe(seed.prop_manifest_json, { hero_props: [], supporting_props: [] }));
const heroProps = Array.isArray(propManifest.hero_props) ? propManifest.hero_props : [];
const supportingProps = Array.isArray(propManifest.supporting_props) ? propManifest.supporting_props : [];
const totalProps = heroProps.length + supportingProps.length;

const allowedModes = Array.isArray(guard.allowed_subject_modes) ? guard.allowed_subject_modes : [];
const envTerms = Array.isArray(guard.anchor_environment_terms) ? guard.anchor_environment_terms : [];
const materialTerms = Array.isArray(guard.anchor_material_terms) ? guard.anchor_material_terms : [];
const gestureTerms = Array.isArray(guard.anchor_gesture_terms) ? guard.anchor_gesture_terms : [];
const bannedPropTerms = Array.isArray(guard.forbidden_prop_terms) ? guard.forbidden_prop_terms : [];
const bannedStyleTerms = Array.isArray(guard.forbidden_style_terms) ? guard.forbidden_style_terms : [];
const bannedPaletteTerms = Array.isArray(guard.forbidden_palette_terms) ? guard.forbidden_palette_terms : [];

const reasons = [];
const driftFlags = [];

if (allowedModes.length && !allowedModes.includes(String(seed.subject_mode || '').trim())) {
  reasons.push(`subject_mode_outside_family:${seed.subject_mode || 'missing'}`);
}

if (heroProps.length > 2) reasons.push('too_many_hero_props');
if (supportingProps.length > 3) reasons.push('too_many_supporting_props');
if (totalProps > 4) reasons.push('too_many_named_props');

if (hasAny(positiveBlob, bannedPropTerms)) {
  reasons.push('banned_prop_term_present');
  driftFlags.push('banned_prop_term_present');
}

if (hasAny(positiveBlob, bannedStyleTerms)) {
  reasons.push('banned_style_term_present');
  driftFlags.push('banned_style_term_present');
}

if (hasAny(positiveBlob, bannedPaletteTerms)) {
  reasons.push('banned_palette_term_present');
  driftFlags.push('banned_palette_term_present');
}

const hardBans = [
  'mri', 'brain scan', 'graph', 'chart', 'diagram', 'spreadsheet', 'dashboard',
  'monitor', 'clipboard', 'contract', 'lease', 'legal form', 'medical form',
  'paperwork', 'infographic', 'office desk', 'conference room'
];

if (hasAny(positiveBlob, hardBans)) {
  reasons.push('hard_banned_editorial_residue');
  driftFlags.push('hard_banned_editorial_residue');
}

const materialHits = hitCount(positiveBlob, materialTerms);
const envHits = hitCount(positiveBlob, envTerms);
const gestureHits = hitCount(positiveBlob, gestureTerms);

if (materialTerms.length && materialHits === 0) reasons.push('family_material_missing');
if (envTerms.length && envHits === 0) reasons.push('family_environment_missing');
if (gestureTerms.length && gestureHits === 0) reasons.push('family_gesture_missing');

const surrealMechanism = clean(seed.surreal_mechanism || '');
const surrealPolicy = guard.surreal_mechanism_policy || {};
if (!surrealMechanism) reasons.push('surreal_mechanism_missing');
if (surrealPolicy.allow_visible_glow === false && hasAny(positiveBlob, ['glow', 'glowing', 'aura', 'halo'])) {
  reasons.push('forbidden_magic_glow');
}
if (surrealPolicy.allow_float_magic === false && hasAny(positiveBlob, ['floating', 'levitating', 'hovering'])) {
  reasons.push('forbidden_float_magic');
}

const criticFloor = Number(guard.critic_score_floor || 8.6);
if (Number(critic.score || 0) < criticFloor) reasons.push('critic_score_below_floor');
if (Number(critic.brand_fit || 0) < criticFloor) reasons.push('brand_fit_below_floor');
if (Number(critic.reference_alignment || 0) < criticFloor) reasons.push('reference_alignment_below_floor');
if (Number(critic.family_guardrail_score || 0) < criticFloor) reasons.push('family_guardrail_below_floor');
if (Number(critic.anti_editorial || 0) < criticFloor) reasons.push('anti_editorial_below_floor');
if (Number(critic.prop_discipline || 0) < 8.2) reasons.push('prop_discipline_low');
if (Number(critic.negative_space_force || 0) < 8.2) reasons.push('negative_space_force_low');

const familyGuardrailScore = Math.max(
  0,
  Math.min(
    10,
    (
      4 +
      Math.min(materialHits, 2) * 1.2 +
      Math.min(envHits, 2) * 1.2 +
      Math.min(gestureHits, 2) * 1.0 -
      reasons.length * 0.7
    )
  )
);

return [{
  json: {
    ...j,
    gate: {
      approve: reasons.length === 0 && critic.approve === true,
      reasons,
      drift_flags: driftFlags,
      family_guardrail_score: Number(familyGuardrailScore.toFixed(2)),
      material_hits: materialHits,
      environment_hits: envHits,
      gesture_hits: gestureHits
    }
  }
}];

function parseStrictJson(raw) {
  const source = typeof raw === 'string'
    ? raw
    : raw?.text ?? raw?.output ?? raw?.result ?? raw?.body?.output_text ?? JSON.stringify(raw);

  const text = String(source || '').trim();
  if (!text) throw new Error('TVPX parser: empty LLM output.');

  const candidates = [
    text,
    text.replace(/\`\`\`json\s*/gi, '').replace(/\`\`\`/g, '').trim(),
  ];

  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch {}
  }

  const stripped = candidates[1];
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const slice = stripped.slice(start, end + 1)
      .replace(/[\u201C\u201D]/g, '"')
      .replace(/[\u2018\u2019]/g, "'")
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']');

    return JSON.parse(slice);
  }

  throw new Error('TVPX parser: could not locate valid JSON.');
}

const base = $items('Parse Scene Seed JSON')[0]?.json;
if (!base) throw new Error('TVPX parser: base node "Parse Scene Seed JSON" missing.');

const parsed = parseStrictJson($json);

return [{
  json: {
    ...base,
    image_native_critic: parsed,
  },
}];

